import { fromNodeHeaders } from 'better-auth/node'
import { getAuth } from '../auth/auth'
import { Request, Response, NextFunction } from 'express'

export async function loadSession(req: Request): Promise<void>
  try:
    const session = await getAuth().api.getSession({ headers: fromNodeHeaders(req.headers) })
    if (session) {
      req.user = { id: session.user.id, admin: Boolean(session.user.admin) }
      req.authSession = session.session
    }
  catch:
    // fail closed: leave req.user undefined (treated as unauthenticated)
    // log error server-side without leaking connection details

export async function requireUser(req: Request, res: Response, next: NextFunction): Promise<void>
  await loadSession(req)
  if (\!req.user) { res.status(401).json({ error: 'Unauthorized' }); return }
  next()

export async function requireAdmin(req: Request, res: Response, next: NextFunction): Promise<void>
  await loadSession(req)
  if (\!req.user) { res.status(401).json({ error: 'Unauthorized' }); return }
  if (\!req.user.admin) { res.status(403).json({ error: 'Forbidden' }); return }
  next()

JSDoc on all three exported functions. Explicit return types. NO 'any' types.

